  --chart-2: #C9A227;
  --chart-3: #6E8B6E;
  --chart-4: #B5502F;
  --chart-5: #8A7B60;
  --radius: 0.75rem;
  --shadow: 0 1px 2px 0 rgb(30 58 95 / 0.08);
  --popover: #FFFDF8;
  --primary: #1E3A5F;
  --spacing: 0.25rem;
  --font-mono: 'IBM Plex Mono', Menlo, monospace;
  --font-sans: 'Cormorant Garamond', 'EB Garamond', Georgia, serif;
